function levenshtein(a, b) {
  const m2 = a.length;
  const n2 = b.length;
  const dp = Array.from({ length: m2 + 1 }, () => Array(n2 + 1).fill(0));
  for (let i = 0; i <= m2; i++) dp[i][0] = i;
  for (let j = 0; j <= n2; j++) dp[0][j] = j;
  for (let i = 1; i <= m2; i++) {
    for (let j = 1; j <= n2; j++) {
      const cost = a[i - 1] === b[j - 1] ? 0 : 1;
      dp[i][j] = Math.min(
        dp[i - 1][j] + 1,
        dp[i][j - 1] + 1,
        dp[i - 1][j - 1] + cost
      );
    }
  }
  return dp[m2][n2];
}
function findClosestKeyword(identifier) {
  const lower = identifier.toLowerCase();
  if (lower.length < 4 || DEFINITION_KEYWORDS.has(lower)) return void 0;
  const maxDistance = lower.length <= 5 ? 1 : 2;
  let bestMatch;
  let bestDist = maxDistance + 1;
  for (const keyword of DEFINITION_KEYWORDS) {
    if (Math.abs(keyword.length - lower.length) > maxDistance) continue;
    const dist = levenshtein(lower, keyword);
    if (dist > 0 && dist < bestDist) {
      bestDist = dist;
      bestMatch = keyword;
    }
  }
  return bestMatch;
}
